import string

def word_frequency(text: str) -> dict[str, int]:
    words = text.lower().split()
    cleaned_words = [word.strip(string.punctuation) for word in words]
    frequency = {}
    for word in cleaned_words:
        if word in frequency:
            frequency[word] += 1
        else:
            frequency[word] = 1
    return frequency
